# 2025 single tax brackets
def ordinary_tax(income):
    tax = 0
    if income > 197300:
        pass # not needed
    if income > 103350:
        pass # not needed
    if income > 48475:
        tax += (income - 48475) * 0.22
        income = 48475
    if income > 11925:
        tax += (income - 11925) * 0.12
        income = 11925
    if income > 0:
        tax += income * 0.10
    return tax

taxable_income = 62645
qdcg = 12942
ord_inc = taxable_income - qdcg
ord_tax = ordinary_tax(ord_inc)

# CG threshold 0% up to $48,350 for single in 2025
if ord_inc >= 48350:
    cg_tax = qdcg * 0.15
else:
    zero_bucket = 48350 - ord_inc
    if qdcg <= zero_bucket:
        cg_tax = 0
    else:
        cg_tax = (qdcg - zero_bucket) * 0.15

print(f"Ord inc: {ord_inc}, Ord Tax: {ord_tax}")
print(f"CG tax: {cg_tax}")
print(f"Total Tax: {round(ord_tax + cg_tax)}")
EOF
python3 tax.py"}

